CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`distribution`.`multi_angle_feed` (
    `multi_angle_feed_id` BIGINT COMMENT '',
    `abr_profile_id` BIGINT COMMENT 'ABR encoding profile for the feed.',
    `channel_id` BIGINT COMMENT 'FK to the channel carrying the angle feed.',
    `playout_feed_id` BIGINT COMMENT 'FK to the parent playout feed',
    `signal_route_id` BIGINT COMMENT 'Signal route carrying the feed.',
    `sports_event_id` BIGINT COMMENT '',
    `streaming_endpoint_id` BIGINT COMMENT 'FK to the streaming endpoint',
    `broadcast_facility_id` BIGINT COMMENT 'Facility originating the angle signal.',
    `employee_id` BIGINT COMMENT 'Operational owner of the angle feed.',
    `_created_at` TIMESTAMP COMMENT 'Record creation timestamp for medallion lineage.',
    `_updated_at` TIMESTAMP COMMENT 'Record last-update timestamp for medallion lineage.',
    `activation_timestamp` TIMESTAMP COMMENT 'When the angle feed went live.',
    `angle_label` STRING COMMENT 'Camera angle label (e.g. high-home, low-tight, skycam, goal-line).',
    `angle_name` STRING COMMENT '',
    `angle_type` STRING COMMENT 'Angle type: iso/4k/replay/skycam/tactical/main',
    `aspect_ratio` DECIMAL(18,2) COMMENT 'Display aspect ratio as numeric value',
    `audio_codec` STRING COMMENT 'Audio codec used for the feed.',
    `audio_configuration` STRING COMMENT 'Audio channel configuration (e.g. stereo, 5.1, Atmos).',
    `audio_track_config` STRING COMMENT 'Audio track configuration for the feed.',
    `available_for_distribution_flag` BOOLEAN COMMENT 'True if the angle feed is made available to downstream distribution/OTT.',
    `available_from_at` TIMESTAMP COMMENT 'When the feed becomes available.',
    `available_to_subscribers_flag` BOOLEAN COMMENT 'Whether the angle is selectable by subscribers.',
    `available_until_at` TIMESTAMP COMMENT 'When the feed availability ends.',
    `bitrate_kbps` STRING COMMENT 'Encoded bitrate in kbps',
    `bitrate_mbps` DECIMAL(18,2) COMMENT 'Encoded bitrate of the feed in megabits per second.',
    `camera_label` STRING COMMENT 'Camera/source label for the angle.',
    `camera_number` STRING COMMENT 'Camera/ISO number on the production switcher.',
    `camera_position` STRING COMMENT 'Physical camera position description',
